# acme_claude/circuit.py
import time, threading

class CircuitBreaker:
    def __init__(self, failure_threshold: int = 5, recovery_seconds: float = 60.0):
        self._threshold = failure_threshold
        self._recovery = recovery_seconds
        self._failures = 0
        self._opened_at: float | None = None
        self._lock = threading.Lock()

    @property
    def is_open(self) -> bool:
        with self._lock:
            if self._opened_at is None:
                return False
            if time.monotonic() - self._opened_at > self._recovery:
                # Half-open: allow one probe
                self._opened_at = None
                self._failures = 0
                return False
            return True

    def record_success(self):
        with self._lock:
            self._failures = 0
            self._opened_at = None

    def record_failure(self):
        with self._lock:
            self._failures += 1
            if self._failures >= self._threshold:
                self._opened_at = time.monotonic()

# acme_claude/budget.py

class BudgetExceeded(RuntimeError):
    pass

def check_budget(used: int, budget: int) -> None:
    """Raise BudgetExceeded if used tokens would exceed the session budget."""
    if used >= budget:
        raise BudgetExceeded(
            f"Session token budget exceeded: {used} >= {budget}. "
            "Increase session_token_budget or split the task."
        )

def record_usage(used: int, additional: int, budget: int) -> int:
    total = used + additional
    if total > budget:
        raise BudgetExceeded(f"Budget exceeded after call: {total} > {budget}")
    return total

// packages/claude/src/client.ts  (published as @acme/claude)
import Anthropic from "@anthropic-ai/sdk";
import { getSecret } from "./secrets";
import { ClaudeMetrics } from "./metrics";

export interface ClaudeClientOptions {
  model?: string;
  maxTokens?: number;
  sessionTokenBudget?: number;
  maxRetries?: number;
  serviceName?: string;
}

export class ClaudeClient {
  private client: Anthropic;
  private model: string;
  private maxTokens: number;
  private budget: number | undefined;
  private tokensUsed = 0;
  private metrics: ClaudeMetrics;

  constructor(opts: ClaudeClientOptions = {}) {
    this.model = opts.model ?? "claude-sonnet-5";
    this.maxTokens = opts.maxTokens ?? 2048;
    this.budget = opts.sessionTokenBudget;
    this.metrics = new ClaudeMetrics(opts.serviceName ?? process.env.SERVICE_NAME ?? "unknown");
    // API key fetched lazily from secrets manager on first call
    this.client = new Anthropic({ apiKey: "placeholder" });
  }

  async complete(
    messages: Anthropic.MessageParam[],
    options?: Partial<Anthropic.MessageCreateParamsNonStreaming>
  ): Promise<Anthropic.Message> {
    if (this.budget !== undefined && this.tokensUsed >= this.budget) {
      throw new Error(`Session token budget exceeded: ${this.tokensUsed} >= ${this.budget}`);
    }
    const apiKey = await getSecret(process.env.ANTHROPIC_SECRET_NAME!);
    (this.client as any).apiKey = apiKey;  // refresh on each call for rotation support

    const start = performance.now();
    const response = await this.client.messages.create({
      model: this.model,
      max_tokens: this.maxTokens,
      messages,
      ...options,
    });
    const latencyMs = performance.now() - start;

    this.metrics.record({ response, latencyMs });
    this.tokensUsed += response.usage.input_tokens + response.usage.output_tokens;
    return response;
  }
}
